const input = $input.first()?.json || {};
const body = input.body && typeof input.body === 'object' ? input.body : input;
const headers = input.headers || {};
const query = input.query && typeof input.query === 'object' ? input.query : {};
const parameters = body.parameters && typeof body.parameters === 'object' ? body.parameters : body;

const config = {
  trabajoya_base_url: 'https://trabajoya.rivasystems.dev',
  trabajoya_interview_api_key: 'PEGAR_TRABAJOYA_INTERVIEW_API_KEY'
};

function clean(value) {
  return String(value || '').trim();
}

function getHeader(name) {
  const target = name.toLowerCase();
  for (const [key, value] of Object.entries(headers)) {
    if (String(key).toLowerCase() === target) return clean(value);
  }
  return '';
}

const expectedKey = clean(config.trabajoya_interview_api_key);
const providedKey = getHeader('x-trabajoya-key') || clean(headers['X-Trabajoya-Key']) || clean(query.trabajoya_key || query.trabajoyaKey);

if (!expectedKey || expectedKey.startsWith('PEGAR_')) {
  throw new Error('Edita el nodo "Validar payload" y pega TRABAJOYA_INTERVIEW_API_KEY.');
}

if (!providedKey || providedKey !== expectedKey) {
  throw new Error('X-Trabajoya-Key invalido para feedback de entrevista.');
}

const sessionId = clean(parameters.interview_session_id || parameters.interviewSessionId || parameters.session_id || parameters.sessionId);

if (!sessionId) {
  throw new Error('Falta interview_session_id.');
}

const payload = {
  interview_session_id: sessionId,
  elevenlabs_conversation_id: clean(
    parameters.elevenlabs_conversation_id ||
      parameters.conversation_id ||
      parameters.conversationId ||
      body.conversation_id ||
      body.conversationId
  ),
  status: clean(parameters.status) || 'completed',
  scores: parameters.scores || {},
  feedback: parameters.feedback || {
    overall_score: parameters.overall_score || parameters.score || 0,
    summary: parameters.summary || '',
    strengths: parameters.strengths || parameters.fortalezas || [],
    improvements: parameters.improvements || parameters.mejoras || [],
    suggested_answers: parameters.suggested_answers || parameters.respuestas_sugeridas || [],
    next_steps: parameters.next_steps || parameters.proximos_pasos || []
  }
};

return [
  {
    json: {
      trabajoya_base_url: clean(config.trabajoya_base_url).replace(/\/$/, ''),
      trabajoya_interview_api_key: expectedKey,
      payload
    }
  }
];
